<?php
declare(strict_types=1);
require dirname(__DIR__) . '/lib/bootstrap.php';
$admin=require_admin(); $adminTitle='Website Settings'; $adminSection='settings'; $error='';

if($_SERVER['REQUEST_METHOD']==='POST'){
    verify_csrf();
    try{
        $textFields=['site_name','site_url','tagline','phone_1','phone_2','email_1','email_2','address','opening_hours','footer_text','social_facebook','social_instagram','social_linkedin','social_youtube','whatsapp_number','whatsapp_message','smtp_host','smtp_port','smtp_encryption','smtp_username','smtp_from_email','smtp_from_name','admin_email'];
        foreach($textFields as $key){$value=trim((string)($_POST[$key]??''));if(str_starts_with($key,'social_')&&$value!==''&&!filter_var($value,FILTER_VALIDATE_URL))throw new RuntimeException('Please enter complete https:// links for social media.');update_setting($key,$value);}
        update_setting('map_embed',sanitize_map_embed((string)($_POST['map_embed']??'')));
        update_setting('mail_enabled',isset($_POST['mail_enabled'])?'1':'0');
        if(trim((string)($_POST['smtp_password']??''))!==''){update_setting('smtp_password_enc',encrypt_secret((string)preg_replace('/\s+/','',(string)$_POST['smtp_password'])));}
        update_setting('logo_main',upload_image('logo_main',(string)setting('logo_main')));
        update_setting('logo_footer',upload_image('logo_footer',(string)setting('logo_footer')));
        if(($_POST['action']??'save')==='test_mail'){
            require_once APP_ROOT.'/lib/mailer.php';
            $mailer=make_mailer();$mailer->addAddress((string)setting('admin_email'));$mailer->Subject='JG Cleaning CMS SMTP test';$mailer->Body=mail_template('Your SMTP settings are working','This test email was sent from the JG Cleaning Services administration panel.','<div style="padding:18px;border-radius:12px;background:#e9f9fd;color:#075e72">PHPMailer connected successfully using the saved website settings.</div>');$mailer->AltBody='JG Cleaning CMS SMTP settings are working.';$mailer->send();
            flash('success','Settings saved and a test email was sent to the admin address.');
        }else flash('success','Website, contact, social and mail settings were saved.');
        redirect(url('admin/settings.php'));
    }catch(Throwable $exception){$error=$exception->getMessage();}
}
require __DIR__.'/includes/header.php';
?>
