<div class="admin-form-actions"><a href="<?= e(url('admin/index.php')) ?>">Cancel</a><div><button class="admin-button admin-button--secondary" type="submit" name="action" value="test_mail">Save &amp; send test email</button><button class="admin-button" type="submit" name="action" value="save">Save all settings</button></div></div></form>
